            [string[]]$result = Get-DockerImageTags @context
            $result | Should -Contain 'pr-42'
        }

        It 'Should NOT return "latest" for a PR on a feature branch' {
            [hashtable]$context = @{
                BranchName = 'feature/my-feature'
                CommitSha  = 'abc1234567890def'
                Tags       = @()
                PrNumber   = [int]42
