[string]$semverPattern = '^v\d+\.\d+\.\d+(-[a-zA-Z0-9.\-]+)?$'
foreach ($tag in $Tags) {
    if ([regex]::IsMatch($tag, $semverPattern)) {
        $result.Add([string]$tag)
    }
}

return [string[]]$result.ToArray()

